//! Integration tests for the CDQN Runtime and Chronosa Agent execution.
//!
//! These tests verify the full Cognitive Cycle (Dispatcher -> Agent -> Logic).

use crate::CdqnRuntime;
use cdqn_cdu::Cdu;
use cdqn_hlc::HybridLogicalClock;
use cdqn_cryptocore::hash_sha3_256;
use cdqn_cdu::payloads::AxiomPayload;
use cdqn_cdu::World;
use std::path::PathBuf;
use std::thread;
use std::time::Duration;
use tempfile::tempdir;

// Helper function to create a test CDU for the simulation
fn create_test_cdu(statement: &str, r_coordinate: f64) -> Cdu {
    let hlc = HybridLogicalClock::new();
    let node_id = hash_sha3_256(b"sim_node").to_vec();
    
    let axiom_payload = AxiomPayload {
        statement: statement.to_string(),
    };
    let payload = axiom_payload.into_payload();

    let metadata = cdqn_cdu::Metadata {
        author_node: node_id.clone(),
        context_refs: vec![],
        state: "draft".to_string(),
        weight: 1.0,
        r_coordinate,
        world_context: World::UserWorld,
        hlc_timestamp: hlc.new_timestamp(),
        symmetric_counterpart: None,
        validated_worlds: std::collections::HashSet::new(),
    };

    // NOTE: We skip the full signing process for simplicity in main.rs
    Cdu::new(payload, metadata, &hlc, &node_id)
}

/// This test verifies the full Cognitive Cycle by injecting CDUs and checking the Agent's output.
#[test]
fn test_full_cognitive_cycle_verifier() {
    let temp_dir = tempdir().unwrap();
    let storage_path = temp_dir.path().to_path_buf();
    
    // 1. Initialize the CDQN Runtime (The Guardrail)
    let runtime = CdqnRuntime::new(storage_path);

    // 2. Start the Verifier Agent on a separate thread
    let dispatcher_clone = runtime.dispatcher.clone_for_agent();
    let manifold_clone = runtime.manifold.clone();

    let agent_handle = thread::spawn(move || {
        let mut verifier = cdqn_chronosa::VerifierAgent::new(&dispatcher_clone, manifold_clone);
        verifier.run();
    });

    // NOTE: We must wait briefly for the VerifierAgent thread to start its polling loop.
    thread::sleep(Duration::from_millis(10));
    
    // --- SIMULATION: Injecting Test CDUs ---
    
    // 3. Inject a Valid CDU (r_coordinate > 1.0)
    let valid_cdu = create_test_cdu("Valid Axiom", 2.5);
    runtime.dispatcher.publish(valid_cdu).expect("Failed to publish Valid CDU");

    // 4. Inject a Contradictory CDU (r_coordinate in Impossibility Zone [0.5])
    let contradictory_cdu = create_test_cdu("Contradictory Fact", 0.5);
    runtime.dispatcher.publish(contradictory_cdu).expect("Failed to publish Contradictory CDU");

    // 5. Give the Verifier Agent time to process the messages
    thread::sleep(Duration::from_millis(50));
    
    // --- Verification ---
    // The Agent's output (println!) will now be captured by the CI log,
    // providing the verifiable proof of the Cognitive Cycle.
    
    // We check the thread is still running (i.e., it didn't panic on the first two messages)
    assert!(!agent_handle.is_finished(), "Verifier Agent thread should not have panicked.");
    
    // To stop the Agent thread gracefully, we would need a shutdown signal,
    // but for this test, we just let it run for a moment and then detach.
    // The thread will be terminated when the test process exits.
}
